class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        const int MAX = 100000;
        vector<bool> isPrime(MAX + 1, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= MAX; ++i) {
            if (isPrime[i]) {
                for (int j = i * i; j <= MAX; j += i) {
                    isPrime[j] = false;
                }
            }
        }

        int n = nums.size();
        vector<int> prefix(n + 1), suffix(n + 2);
        vector<int> lastSeen(MAX + 1, -1);

        auto buildPrefix = [&]() {
            fill(lastSeen.begin(), lastSeen.end(), -1);
            prefix[0] = 0;
            for (int i = 0; i < n; ++i) {
                int val = nums[i];
                prefix[i + 1] = prefix[i];
                if (isPrime[val]) {
                    if (lastSeen[val] == -1) {
                        prefix[i + 1]++;
                    }
                    lastSeen[val] = i;
                }
            }
        };

        auto buildSuffix = [&]() {
            fill(lastSeen.begin(), lastSeen.end(), -1);
            suffix[n] = 0;
            for (int i = n - 1; i >= 0; --i) {
                int val = nums[i];
                suffix[i] = suffix[i + 1];
                if (isPrime[val]) {
                    if (lastSeen[val] == -1) {
                        suffix[i]++;
                    }
                    lastSeen[val] = i;
                }
            }
        };

        buildPrefix();
        buildSuffix();

        vector<int> res;
        res.reserve(queries.size());

        for (const auto& q : queries) {
            int idx = q[0], val = q[1];
            nums[idx] = val;

            buildPrefix();
            buildSuffix();

            int maxSum = 0;
            for (int k = 1; k < n; ++k) {
                int left = prefix[k];
                int right = suffix[k];
                maxSum = max(maxSum, left + right);
            }
            res.push_back(maxSum);
        }

        return res;
    }
};
